import axios from 'axios';
import { fetchWithCache, clearCache } from './cacheService';

// Configuration de base
const apiService = {
  /**
   * Effectue une requête GET avec mise en cache
   * @param {string} url - URL de la requête
   * @param {object} config - Configuration axios
   * @param {number} cacheMinutes - Durée de mise en cache en minutes
   */
  async get(url, config = {}, cacheMinutes = 5) {
    try {
      // Utiliser fetchWithCache au lieu d'axios pour les requêtes GET
      const response = await fetchWithCache(
        axios.defaults.baseURL + url,
        {
          ...config,
          headers: {
            ...config.headers,
            Authorization: axios.defaults.headers.common['Authorization']
          }
        },
        cacheMinutes
      );

      const data = await response.json();
      return { data, status: response.status };
    } catch (error) {
      console.error(`Erreur GET pour ${url}:`, error);
      throw error;
    }
  },

  /**
   * Effectue une requête POST standard (sans cache)
   */
  async post(url, data, config = {}) {
    try {
      // Invalider le cache pour les URLs associées
      this.invalidateRelatedCache(url);
      return await axios.post(url, data, config);
    } catch (error) {
      console.error(`Erreur POST pour ${url}:`, error);
      throw error;
    }
  },

  /**
   * Effectue une requête PUT standard (sans cache)
   */
  async put(url, data, config = {}) {
    try {
      // Invalider le cache pour les URLs associées
      this.invalidateRelatedCache(url);
      return await axios.put(url, data, config);
    } catch (error) {
      console.error(`Erreur PUT pour ${url}:`, error);
      throw error;
    }
  },

  /**
   * Effectue une requête DELETE standard (sans cache)
   */
  async delete(url, config = {}) {
    try {
      // Invalider le cache pour les URLs associées
      this.invalidateRelatedCache(url);
      return await axios.delete(url, config);
    } catch (error) {
      console.error(`Erreur DELETE pour ${url}:`, error);
      throw error;
    }
  },

  /**
   * Invalide le cache pour les URLs associées
   * Par exemple, si on modifie un quiz, on invalide le cache des listes de quiz
   */
  invalidateRelatedCache(url) {
    // Exemples de règles d'invalidation
    if (url.includes('/quizzes/')) {
      clearCache(); // Pour simplifier, on vide tout le cache
    }
    if (url.includes('/users/')) {
      clearCache(); // Pour simplifier, on vide tout le cache
    }
  }
};

export default apiService;
